#include <stdio.h>
#include <string.h>

int main() {
  char s1[50] = "Hello";
  char s2[] = " World";
  printf("Length: %zu\n", strlen(s1));
  strcat(s1, s2);
  printf("Concat: %s\n", s1);
  printf("Compare: %d\n", strcmp("abc", "abc"));
  printf("Compare: %d\n", strcmp("abc", "abd"));
  char *found = strchr(s1, 'W');
  if (found) printf("Found: %s\n", found);
  return 0;
}
